import './PaginationCollapsible.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useCallback, useEffect, useMemo, useState } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import { PaginationCell } from '../PaginationCell';
import { getPage } from '../utils';
import type { PaginationCollapsibleProps } from './PaginationCollapsible.types';
import { getFinish, getStart } from './utils';

export const PaginationCollapsible: FC<PaginationCollapsibleProps> = ({
	count,
	siblingCount = 3,
	page = 1,
	onChange,
	className,
	...props
}) => {
	const [_page, _setPage] = useState<number>(getPage(page, count));

	// Кэшируем функцию установки индекса
	const setNewIndex = useCallback(
		(newIndex: number): void => {
			if (newIndex === _page) {
				return;
			}
			_setPage(newIndex);
			onChange?.(newIndex);
		},
		[_page, onChange],
	);

	// Кэшируем обработчик клика
	const handleCellClick = useCallback(
		(newIndex: number): void => {
			setNewIndex(newIndex);
		},
		[setNewIndex],
	);

	// Кэшируем вычисление ячеек страниц
	const siblingCell = useMemo(() => {
		const cells: React.ReactNode[] = [];
		const start = getStart(_page, count, siblingCount);
		const finish = getFinish(start, _page, count, siblingCount);

		if (!start || !finish) {
			return cells;
		}

		for (let i = start; i <= finish; i++) {
			const cellIndex = i;
			cells.push(
				<li key={cellIndex}>
					<PaginationCell variant="text" active={_page === cellIndex} onClick={() => handleCellClick(cellIndex)}>
						{cellIndex}
					</PaginationCell>
				</li>,
			);
		}
		return cells;
	}, [_page, count, siblingCount, handleCellClick]);

	// Обновление при изменении внешней страницы
	useEffect(() => {
		_setPage(getPage(page, count));
	}, [page, count]);

	const handleDecreaseClick = useCallback(() => {
		const newIndex = _page - 1;
		if (newIndex >= 1) {
			setNewIndex(newIndex);
		}
	}, [_page, setNewIndex]);

	const handleIncreaseClick = useCallback(() => {
		const newIndex = _page + 1;
		if (newIndex <= count) {
			setNewIndex(newIndex);
		}
	}, [_page, count, setNewIndex]);

	const handleFirstCellClick = useCallback(() => {
		handleCellClick(1);
	}, [handleCellClick]);

	const handleLastCellClick = useCallback(() => {
		handleCellClick(count);
	}, [count, handleCellClick]);

	// Кэшируем компоненты
	const navArrowLeft = useMemo(
		() => (
			<li key={0}>
				<PaginationCell
					variant="icon"
					disabled={_page === 1}
					startIcon={<Icon iconName={Icons.NavArrowLeft} size="large" />}
					onClick={handleDecreaseClick}
					className="dsb_pagination-cell__first"
				/>
			</li>
		),
		[_page, handleDecreaseClick],
	);

	const navArrowRight = useMemo(
		() => (
			<li key={count ? count + 1 : 2}>
				<PaginationCell
					variant="icon"
					disabled={_page === count}
					startIcon={<Icon iconName={Icons.NavArrowRight} size="large" />}
					onClick={handleIncreaseClick}
				/>
			</li>
		),
		[_page, count, handleIncreaseClick],
	);

	const increaseDots = useMemo(
		() => (
			<li key={'increase-dots'}>
				<PaginationCell
					variant="icon"
					startIcon={<Icon iconName={Icons.MoreHoriz} size="large" />}
					className="dsb_pagination-cell__increase-dots"
				/>
			</li>
		),
		[],
	);

	const decreaseDots = useMemo(
		() => (
			<li key={'decrease-dots'}>
				<PaginationCell
					variant="icon"
					startIcon={<Icon iconName={Icons.MoreHoriz} size="large" />}
					className="dsb_pagination-cell__decrease-dots"
				/>
			</li>
		),
		[],
	);

	const firstCell = useMemo(
		() => (
			<li key={1}>
				<PaginationCell
					variant="text"
					active={_page === 1}
					onClick={handleFirstCellClick}
					className="dsb_pagination-cell__first-cell"
				>
					{1}
				</PaginationCell>
			</li>
		),
		[_page, handleFirstCellClick],
	);

	const lastCell = useMemo(
		() => (
			<li key={count}>
				<PaginationCell
					variant="text"
					active={_page === count}
					onClick={handleLastCellClick}
					className="dsb_pagination-cell__last-cell"
				>
					{count}
				</PaginationCell>
			</li>
		),
		[_page, count, handleLastCellClick],
	);

	const showDecreaseDots = useMemo(
		() => _page > siblingCount + 1 && siblingCount + 3 < count,
		[_page, siblingCount, count],
	);

	const showIncreaseDots = useMemo(
		() => count - _page - 1 >= siblingCount && siblingCount + 3 < count,
		[_page, siblingCount, count],
	);

	return (
		<ul
			data-testid="PaginationCollapsible"
			className={classNames('dsb_pagination dsb_pagination__collapsed', className)}
			{...props}
		>
			{navArrowLeft}
			{firstCell}
			{showDecreaseDots && decreaseDots}
			{siblingCell}
			{showIncreaseDots && increaseDots}
			{count > 1 && lastCell}
			{navArrowRight}
		</ul>
	);
};
